patch:
--- a/alu.v
+++ b/alu.v
@@ -1,15 +1,15 @@
 module alu_32bit(
   input [31:0] operand_a, operand_b,
   input [2:0] opcode,
   output reg [31:0] result
 );

-  always @(opcode)
+  always @(*)
     case (opcode)
       3'b000: result = operand_a + operand_b;
       3'b001: result = operand_a - operand_b;
       3'b010: result = operand_a & operand_b;
       3'b011: result = operand_a | operand_b;
       3'b100: result = operand_a ^ operand_b;
       default: result = 32'h00000000;
     endcase

 endmodule

before_code:
module alu_32bit(
  input [31:0] operand_a, operand_b,
  input [2:0] opcode,
  output reg [31:0] result
);

  always @(opcode)
    case (opcode)
      3'b000: result = operand_a + operand_b;
      3'b001: result = operand_a - operand_b;
      3'b010: result = operand_a & operand_b;
      3'b011: result = operand_a | operand_b;
      3'b100: result = operand_a ^ operand_b;
      default: result = 32'h00000000;
    endcase

endmodule

after_code:
module alu_32bit(
  input [31:0] operand_a, operand_b,
  input [2:0] opcode,
  output reg [31:0] result
);

  always @(*)
    case (opcode)
      3'b000: result = operand_a + operand_b;
      3'b001: result = operand_a - operand_b;
      3'b010: result = operand_a & operand_b;
      3'b011: result = operand_a | operand_b;
      3'b100: result = operand_a ^ operand_b;
      default: result = 32'h00000000;
    endcase

endmodule
